import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.CQMe4Urg.js";const c=JSON.parse('{"title":"第 2 章 · LLM 原理","description":"","frontmatter":{},"headers":[],"relativePath":"02-llm-fundamentals/index.md","filePath":"02-llm-fundamentals/index.md","lastUpdated":1776333512000}'),o={name:"02-llm-fundamentals/index.md"};function n(d,a,i,h,s,m){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="第-2-章-·-llm-原理" tabindex="-1">第 2 章 · LLM 原理 <a class="header-anchor" href="#第-2-章-·-llm-原理" aria-label="Permalink to &quot;第 2 章 · LLM 原理&quot;">​</a></h1><p>大语言模型（LLM）是 Agent 的&quot;大脑&quot;。你不需要能训练一个模型，但你需要理解它是怎么工作的 -- 就像你不需要造发动机，但开车得知道油门和刹车的原理。</p><h2 id="本章三层结构" tabindex="-1">本章三层结构 <a class="header-anchor" href="#本章三层结构" aria-label="Permalink to &quot;本章三层结构&quot;">​</a></h2><h3 id="初级-llm-是什么" tabindex="-1">初级：LLM 是什么 <a class="header-anchor" href="#初级-llm-是什么" aria-label="Permalink to &quot;初级：LLM 是什么&quot;">​</a></h3><p>用通俗的语言解释 LLM 的核心概念。什么是 Token，主流模型有哪些，为什么会&quot;幻觉&quot;。学完能在团队里聊 AI 不露怯。</p><h3 id="中级-transformer-怎么工作" tabindex="-1">中级：Transformer 怎么工作 <a class="header-anchor" href="#中级-transformer-怎么工作" aria-label="Permalink to &quot;中级：Transformer 怎么工作&quot;">​</a></h3><p>深入注意力机制的直觉理解，搞清楚 Q/K/V 到底在干什么，理解 Temperature 和 Top-p 如何影响输出。学完能解释模型参数调优的原理。</p><h3 id="高级-底层优化" tabindex="-1">高级：底层优化 <a class="header-anchor" href="#高级-底层优化" aria-label="Permalink to &quot;高级：底层优化&quot;">​</a></h3><p>用代码实现注意力计算，理解 KV Cache、Flash Attention 等工程优化，了解模型量化。学完能理解推理引擎在做什么。</p><h2 id="学完能做到" tabindex="-1">学完能做到 <a class="header-anchor" href="#学完能做到" aria-label="Permalink to &quot;学完能做到&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>学完你能</th></tr></thead><tbody><tr><td>初级</td><td>理解 AI 的基本工作方式，对 Token 和模型选择有清晰认识</td></tr><tr><td>中级</td><td>理解 Transformer 架构，能解释模型参数对输出的影响</td></tr><tr><td>高级</td><td>理解底层优化原理，能评估推理性能瓶颈</td></tr></tbody></table><h2 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h2><ul><li>初级：无前置要求</li><li>中级：基础线性代数概念（矩阵乘法）</li><li>高级：能写 Python，了解 numpy 基础</li></ul>',13)])])}const p=t(o,[["render",n]]);export{c as __pageData,p as default};
